/**
 * STLC Pipeline - Step 4: Parse Test Results
 *
 * Reads the JSON test report generated by Playwright
 * and extracts failed test details for Jira ticket creation.
 */

const fs = require('fs');
const path = require('path');

const config = require(path.join(__dirname, '..', 'config', 'project_config.js'));

function parseResults() {
  console.log('\n--- Step 4: Parsing Test Results ---\n');

  const resultsPath = path.resolve(__dirname, '..', 'reports', 'results.json');

  if (!fs.existsSync(resultsPath)) {
    console.log('  ERROR: results.json not found. Run tests first (Step 3).');
    return { total: 0, passed: 0, failed: 0, failures: [] };
  }

  const rawData = fs.readFileSync(resultsPath, 'utf-8');
  const report = JSON.parse(rawData);

  const failures = [];
  let total = 0;
  let passed = 0;
  let failed = 0;

  // Navigate the Playwright JSON report structure
  for (const suite of report.suites || []) {
    for (const innerSuite of suite.suites || []) {
      for (const spec of innerSuite.specs || []) {
        total++;
        const testResult = spec.tests?.[0]?.results?.[0];

        if (testResult?.status === 'passed' || spec.ok) {
          passed++;
        } else {
          failed++;
          failures.push({
            title: spec.title,
            file: suite.file || 'unknown',
            error: testResult?.error?.message || 'Unknown error',
            snippet: testResult?.error?.snippet || '',
            duration: testResult?.duration || 0,
          });
        }
      }
    }
  }

  console.log(`  Total tests:  ${total}`);
  console.log(`  Passed:       ${passed}`);
  console.log(`  Failed:       ${failed}`);

  if (failures.length > 0) {
    console.log('\n  Failed tests:');
    failures.forEach((f, i) => {
      console.log(`    ${i + 1}. ${f.title}`);
      console.log(`       File: ${f.file}`);
      console.log(`       Error: ${f.error.substring(0, 80)}...`);
    });
  }

  return { total, passed, failed, failures };
}

if (require.main === module) {
  parseResults();
}

module.exports = { parseResults };
